import { useEffect, useState } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { getItemById, createItem, updateItem, getCategories } from '../api/inventory';

const LOCATIONS = [
  'Warehouse A', 'Warehouse B',
  'Shelf A-1', 'Shelf A-2', 'Shelf A-3',
  'Shelf B-1', 'Shelf B-2', 'Shelf B-3',
  'Shelf C-1', 'Shelf C-2',
];

const EMPTY = {
  name: '', category_id: '', stock_count: '', price: '', location: '', velocity_status: 'medium',
};

export default function ItemDetail() {
  const { id }    = useParams();
  const navigate  = useNavigate();
  const isNew     = id === 'new';

  const [form, setForm]             = useState(EMPTY);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading]       = useState(!isNew);
  const [saving, setSaving]         = useState(false);
  const [error, setError]           = useState('');
  const [success, setSuccess]       = useState('');

  useEffect(() => {
    getCategories().then(setCategories);
    if (!isNew) {
      getItemById(id)
        .then((item) => {
          if (!item) { navigate('/inventory'); return; }
          setForm({
            name:            item.name,
            category_id:     item.category_id,
            stock_count:     item.stock_count,
            price:           item.price,
            location:        item.location,
            velocity_status: item.velocity_status,
          });
        })
        .finally(() => setLoading(false));
    }
  }, [id, isNew, navigate]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');
    setSaving(true);

    const payload = {
      ...form,
      category_id: Number(form.category_id),
      stock_count: Number(form.stock_count),
      price:       parseFloat(form.price),
    };

    try {
      if (isNew) {
        const created = await createItem(payload);
        setSuccess('Item created successfully.');
        setTimeout(() => navigate(`/inventory/${created.id}`), 800);
      } else {
        await updateItem(id, payload);
        setSuccess('Changes saved.');
        setTimeout(() => setSuccess(''), 2500);
      }
    } catch {
      setError('Failed to save. Please try again.');
    } finally {
      setSaving(false);
    }
  };

  // Reusable field wrapper
  const inputCls = "w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 text-slate-100 placeholder-slate-500 focus:outline-none focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500/40 transition-colors";
  const labelCls = "block text-xs uppercase tracking-widest text-slate-500 mb-2";

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="w-8 h-8 border-2 border-cyan-500 border-t-transparent rounded-full animate-spin" />
      </div>
    );
  }

  return (
    <div className="max-w-2xl w-full space-y-5 sm:space-y-6">
      {/* Breadcrumb */}
      <nav className="flex items-center gap-2 text-sm text-slate-500">
        <Link to="/inventory" className="hover:text-slate-300 transition-colors">Inventory</Link>
        <span>/</span>
        <span className="text-slate-300 truncate">
          {isNew ? 'New Item' : form.name || `Item #${id}`}
        </span>
      </nav>

      <div>
        <h1 className="text-xl sm:text-2xl font-semibold text-slate-100">
          {isNew ? 'Add New Item' : 'Edit Item'}
        </h1>
        <p className="text-sm text-slate-500 mt-1">
          {isNew ? 'Fill in the details below' : `ID #${id}`}
        </p>
      </div>

      {error   && (
        <div className="rounded-xl bg-rose-500/10 border border-rose-500/20 px-4 py-3 text-sm text-rose-300">
          {error}
        </div>
      )}
      {success && (
        <div className="rounded-xl bg-emerald-500/10 border border-emerald-500/20 px-4 py-3 text-sm text-emerald-300">
          {success}
        </div>
      )}

      <form onSubmit={handleSubmit} className="bg-slate-900 border border-slate-800 rounded-2xl p-4 sm:p-6 space-y-4 sm:space-y-5">
        {/* Item Name */}
        <div>
          <label className={labelCls}>Item Name</label>
          <input
            type="text"
            name="name"
            value={form.name}
            onChange={handleChange}
            required
            placeholder="e.g. MacBook Pro 14&quot;"
            className={inputCls}
          />
        </div>

        {/* Category + Velocity — stack on xs, side-by-side on sm+ */}
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <div>
            <label className={labelCls}>Category</label>
            <select
              name="category_id"
              value={form.category_id}
              onChange={handleChange}
              required
              className={inputCls}
            >
              <option value="">Select category</option>
              {categories.map((c) => (
                <option key={c.id} value={c.id}>{c.name}</option>
              ))}
            </select>
          </div>

          <div>
            <label className={labelCls}>Velocity</label>
            <select
              name="velocity_status"
              value={form.velocity_status}
              onChange={handleChange}
              className={inputCls}
            >
              <option value="fast">Fast</option>
              <option value="medium">Medium</option>
              <option value="slow">Slow</option>
            </select>
          </div>
        </div>

        {/* Stock + Price — stack on xs, side-by-side on sm+ */}
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <div>
            <label className={labelCls}>Stock Count</label>
            <input
              type="number"
              name="stock_count"
              value={form.stock_count}
              onChange={handleChange}
              required
              min="0"
              placeholder="0"
              className={inputCls}
            />
          </div>
          <div>
            <label className={labelCls}>Price ($)</label>
            <input
              type="number"
              name="price"
              value={form.price}
              onChange={handleChange}
              required
              min="0"
              step="0.01"
              placeholder="0.00"
              className={inputCls}
            />
          </div>
        </div>

        {/* Location */}
        <div>
          <label className={labelCls}>Location</label>
          <select
            name="location"
            value={form.location}
            onChange={handleChange}
            required
            className={inputCls}
          >
            <option value="">Select location</option>
            {LOCATIONS.map((l) => (
              <option key={l} value={l}>{l}</option>
            ))}
          </select>
        </div>

        {/* Actions */}
        <div className="flex flex-wrap items-center gap-3 pt-2">
          <button
            type="submit"
            disabled={saving}
            className="flex items-center gap-2 bg-cyan-500 hover:bg-cyan-400 disabled:bg-cyan-500/40 disabled:cursor-not-allowed text-slate-950 font-semibold rounded-xl px-5 sm:px-6 py-2.5 transition-colors"
          >
            {saving ? (
              <>
                <svg className="w-4 h-4 animate-spin" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8H4z"/>
                </svg>
                Saving…
              </>
            ) : isNew ? 'Create Item' : 'Save Changes'}
          </button>
          <Link
            to="/inventory"
            className="text-sm text-slate-400 hover:text-slate-200 transition-colors px-4 py-2.5"
          >
            Cancel
          </Link>
        </div>
      </form>
    </div>
  );
}
